script:
// ============================
// HELPER FUNCTIONS
// ============================

// Check if document is submitted
const isDocSubmitted = (frm) => frm.doc.docstatus === 1;

// Set value with submission override
const safeSetValue = (frm, field, value) => {
    if (isDocSubmitted(frm)) {
        // Directly update doc value and refresh field
        frm.doc[field] = value;
        frm.refresh_field(field);
    } else {
        frm.set_value(field, value);
    }
};

// Fetch customer rates
const updateCustomerRate = (frm, height) => {
    return new Promise((resolve) => {
        let rates = {
            customer_rate: 0,
            reengraving_rate: 0
        };

        let completed = 0;

        const checkDone = () => {
            if (++completed === 2) {
                const specialRate = frm.doc.custom_special_rate;
                const specialReengravingRate = frm.doc.custom_special_reengraving_rate;
        
                safeSetValue(frm, 'custom_customer_rate', specialRate || rates.customer_rate);
                safeSetValue(frm, 'custom_customer_reengraving_rate', specialReengravingRate || rates.reengraving_rate);
                resolve();
            }
        };

        fetchRate(frm, frm.doc.customer, 'custom_f', height, (rate) => {
            rates.customer_rate = rate;
            checkDone();
        });

        fetchRate(frm, frm.doc.customer, 'custom_s', height, (rate) => {
            rates.reengraving_rate = rate;
            checkDone();
        });
    });
};

// Fetch rate from customer
const fetchRate = (frm, customer, prefix, height, callback) => {
    frappe.db.get_value('Customer', customer, [
        `${prefix}400`, `${prefix}600`, `${prefix}800`,
        `${prefix}1000`, `${prefix}1500`, `${prefix}2000`
    ], (value) => {
        let rate = 0;

        if (height > 1 && height <= 400) {
            rate = value[`${prefix}400`] || 0;
        } else if (height > 400 && height <= 600) {
            rate = value[`${prefix}600`] || 0;
        } else if (height > 600 && height <= 800) {
            rate = value[`${prefix}800`] || 0;
        } else if (height > 800 && height <= 1000) {
            rate = value[`${prefix}1000`] || 0;
        } else if (height > 1000 && height <= 1500) {
            rate = value[`${prefix}1500`] || 0;
        } else if (height > 1500 && height <= 2000) {
            rate = value[`${prefix}2000`] || 0;
        }

        callback(rate);
    });
};

// Calculate cylinder values
const calculateValues = (frm) => {
    try {
        const {
            custom_design_hight,
            custom_steps,
            custom_design_width,
            custom_repeats,
            custom_r_width,
            custom_additional_width,
            custom_pie_value
        } = frm.doc;

        const custom_fab_roll = flt(frm.doc.custom_fab_roll);
        const custom_sup_roll = flt(frm.doc.custom_sup_roll);
        const custom_no_of_cylinders = custom_fab_roll + custom_sup_roll;

        safeSetValue(frm, 'custom_no_of_cylinders', custom_no_of_cylinders);

        const finalHeight = (flt(custom_design_hight) * flt(custom_steps)).toFixed(2);
        const materialWidth = (flt(custom_design_width) * flt(custom_repeats)).toFixed(2);
        const fullWidth = (flt(materialWidth) + flt(custom_r_width) + flt(custom_additional_width)).toFixed(2);

        safeSetValue(frm, 'custom_final_height', parseFloat(finalHeight));
        safeSetValue(frm, 'custom_material_width', parseFloat(materialWidth));
        safeSetValue(frm, 'custom_full_width', parseFloat(fullWidth));

        const finalDia = flt(finalHeight) / 3.1416;
        safeSetValue(frm, 'custom_final_dia', parseFloat(finalDia.toFixed(2)));

        const msDia = flt(finalHeight) < 850 ? finalDia - 0.20 : finalDia - 0.25;
        safeSetValue(frm, 'custom_ms_dia', parseFloat(msDia.toFixed(2)));

        const cylinderDiameter = (flt(finalHeight) / flt(custom_pie_value)).toFixed(2);
        safeSetValue(frm, 'custom_cylinder_diameter', parseFloat(cylinderDiameter));

        const singleTMM = (flt(finalHeight) * flt(fullWidth) / 1000).toFixed(2);
        safeSetValue(frm, 'custom_single_tmm', singleTMM);

        const totalTMM = (flt(singleTMM) * custom_no_of_cylinders).toFixed(2);
        safeSetValue(frm, 'custom_cylinder_tmm', totalTMM);

        safeSetValue(frm, 'custom_pipe_diameter', Math.round(flt(cylinderDiameter) + 3));
        safeSetValue(frm, 'custom_pipe_thickness', calculatePipeThickness(flt(cylinderDiameter)));

        const pipeKg = calculatePipeKg(frm.doc.custom_pipe_diameter, frm.doc.custom_pipe_thickness, fullWidth);
        safeSetValue(frm, 'custom_pipe_kg', parseFloat(pipeKg.toFixed(2)));
    } catch (error) {
        console.error("Error in calculating values: ", error);
    }
};

// Calculate pipe thickness
const calculatePipeThickness = (cylinderDiameter) => cylinderDiameter <= 273 ? 8 : (cylinderDiameter <= 356 ? 10 : 12);

// Calculate pipe weight
const calculatePipeKg = (outerDiameter, thickness, length) => {
    try {
        const innerDiameter = outerDiameter - 2 * flt(thickness);
        const volume = Math.PI * ((outerDiameter / 2) ** 2 - (innerDiameter / 2) ** 2) * flt(length);
        return (volume / 1000000) * 7.85;
    } catch (error) {
        return 0;
    }
};

// Update billing items
const updateBillingAmount = (frm) => {
    try {
        // Skip if submitted or items table not ready
        if (isDocSubmitted(frm)) return;
        if (!frm.doc.items) return;
        
        const jobType = frm.doc.custom_jobtype;
        const deliveryDate = frm.doc.delivery_date;
        const tmm_per_cylinder = flt(frm.doc.custom_cylinder_tmm) / flt(frm.doc.custom_no_of_cylinders || 1);

        const FAB_GROUP = ["FABG", "CFAB"];
        const SUP_GROUP = ["SUPG", "CSUP"];
        const FOC_GROUP = ["SFOC", "CFOC"];
        const RETURN_GROUP = ["AIIR"];
        const DCRC_GROUP = ["DCRC"];

        const allRelevantItemCodes = [
            "Engraving Cylinder",
            "Engraving Cylinder Supplied",
            "Engraving Cylinder FOC",
            "Engraving Cylinder as is Return"
        ];

        let itemsToAdd = [];

        if (FAB_GROUP.includes(jobType)) {
            itemsToAdd.push({
                code: "Engraving Cylinder",
                qty: frm.doc.custom_fab_roll,
                rate: flt(frm.doc.custom_customer_rate) * tmm_per_cylinder
            });
        } else if (SUP_GROUP.includes(jobType)) {
            itemsToAdd.push({
                code: "Engraving Cylinder Supplied",
                qty: frm.doc.custom_sup_roll,
                rate: flt(frm.doc.custom_customer_reengraving_rate) * tmm_per_cylinder
            });
        } else if (DCRC_GROUP.includes(jobType)) {
            itemsToAdd.push({
                code: "Engraving Cylinder Supplied",
                qty: frm.doc.custom_sup_roll,
                rate: flt(frm.doc.custom_dcrc_rate) * tmm_per_cylinder
            });
        } else if (FOC_GROUP.includes(jobType)) {
            itemsToAdd.push({
                code: "Engraving Cylinder FOC",
                qty: frm.doc.custom_no_of_cylinders,
                rate: 0
            });
        } else if (RETURN_GROUP.includes(jobType)) {
            itemsToAdd.push({
                code: "Engraving Cylinder as is Return",
                qty: frm.doc.custom_no_of_cylinders,
                rate: 0
            });
        } else if (jobType === "MIX") {
            itemsToAdd.push(
                {
                    code: "Engraving Cylinder",
                    qty: frm.doc.custom_fab_roll,
                    rate: flt(frm.doc.custom_customer_rate) * tmm_per_cylinder
                },
                {
                    code: "Engraving Cylinder Supplied",
                    qty: frm.doc.custom_sup_roll,
                    rate: flt(frm.doc.custom_customer_reengraving_rate) * tmm_per_cylinder
                }
            );
        } else {
            itemsToAdd.push({
                code: "Engraving Cylinder",
                qty: frm.doc.custom_no_of_cylinders,
                rate: 0
            });
        }

        // Remove previously relevant items
        frm.doc.items = frm.doc.items.filter(item => {
            const code = item.item_code || '';
            const quantity = flt(item.qty);
            return code && quantity > 0 && !allRelevantItemCodes.includes(code);
        });

        // Add or update items
        itemsToAdd.forEach(({ code, qty, rate }) => {
            if (!qty || qty <= 0) return;

            frm.add_child("items", {
                item_code: code,
                item_name: code,
                uom: "Nos",
                conversion_factor: 1,
                qty: Math.round(flt(qty)),
                delivery_date: deliveryDate,
                rate: parseFloat(flt(rate)).toFixed(2)
            });
        });

        frm.refresh_field("items");
    } catch (error) {
        console.error("Error updating billing amount: ", error);
    }
};

// Handle custom field changes
const handleCustomFieldChange = (frm) => {
    calculateValues(frm);

    const height = frm.doc.custom_final_height;
    if (height) {
        updateCustomerRate(frm, height).then(() => {
            if (!isDocSubmitted(frm)) {
                updateBillingAmount(frm);
            }
        });
    } else if (!isDocSubmitted(frm)) {
        updateBillingAmount(frm);
    }
};

// Update field visibility based on job type
const updateFieldVisibility = (frm) => {
    const jobType = frm.doc.custom_jobtype;

    const FAB_GROUP = ["FABG", "CFAB"];
    const SUP_GROUP = ["SUPG", "CSUP", "SFOC", "CFOC", "AIIR"];
    const FOC_GROUP = ["SFOC", "CFOC", "AIIR"];
    const DCRC_GROUP = ["DCRC"];
    const MIX_GROUP = ["MIX"];

    // Reset values
    safeSetValue(frm, 'custom_fab_roll', 0);
    safeSetValue(frm, 'custom_sup_roll', 0);

    // Determine visibility
    const showFab = FAB_GROUP.includes(jobType) || MIX_GROUP.includes(jobType);
    const showSup = SUP_GROUP.includes(jobType) || DCRC_GROUP.includes(jobType) || MIX_GROUP.includes(jobType);
    const showDcrcRate = DCRC_GROUP.includes(jobType);

    const showSpecialRate = FAB_GROUP.includes(jobType) || MIX_GROUP.includes(jobType);
    const showSpecialReengravingRate = (SUP_GROUP.includes(jobType) && !FOC_GROUP.includes(jobType)) || MIX_GROUP.includes(jobType);

    const showCustomerRate = FAB_GROUP.includes(jobType) || MIX_GROUP.includes(jobType);
    const showCustomerReengravingRate = (SUP_GROUP.includes(jobType) && !FOC_GROUP.includes(jobType)) || MIX_GROUP.includes(jobType);

    frm.set_df_property('custom_fab_roll', 'hidden', !showFab);
    frm.set_df_property('custom_sup_roll', 'hidden', !showSup);
    frm.set_df_property('custom_dcrc_rate', 'hidden', !showDcrcRate);
    frm.set_df_property('custom_special_rate', 'hidden', !showSpecialRate);
    frm.set_df_property('custom_special_reengraving_rate', 'hidden', !showSpecialReengravingRate);
    frm.set_df_property('custom_customer_rate', 'hidden', !showCustomerRate);
    frm.set_df_property('custom_customer_reengraving_rate', 'hidden', !showCustomerReengravingRate);

    frm.refresh_fields([
        'custom_fab_roll',
        'custom_sup_roll',
        'custom_dcrc_rate',
        'custom_special_rate',
        'custom_special_reengraving_rate',
        'custom_customer_rate',
        'custom_customer_reengraving_rate'
    ]);
};

// ============================
// SALES ORDER FORM CONTROLS
// ============================

frappe.ui.form.on("Sales Order", {
    refresh(frm) {
        // Enable saving for submitted documents
        if (isDocSubmitted(frm)) {
            frm.enable_save();
            
            // Make items table read-only
            frm.set_df_property('items', 'read_only', 1);
            
            // Bypass field protection for specific fields
            const customFields = [
                'custom_customer_rate', 'custom_customer_reengraving_rate',
                'custom_special_rate', 'custom_special_reengraving_rate',
                'custom_dcrc_rate', 'custom_final_height', 'custom_jobtype',
                'custom_fab_roll', 'custom_sup_roll', 'custom_no_of_cylinders',
                'custom_design_hight', 'custom_steps', 'custom_design_width',
                'custom_repeats', 'custom_r_width', 'custom_additional_width',
                'custom_pie_value'
            ];
            
            customFields.forEach(field => {
                frm.set_df_property(field, 'allow_on_submit', 1);
                frm.set_df_property(field, 'read_only', 0);
            });
        }

        // Set onchange for all custom fields
        Object.keys(frm.fields_dict).filter(field => field.startsWith('custom_')).forEach(field => {
            frm.fields_dict[field].df.onchange = () => handleCustomFieldChange(frm);
        });

        // Delivery date change handler
        frm.fields_dict['delivery_date'].df.onchange = () => {
            if (!isDocSubmitted(frm)) updateBillingAmount(frm);
        };

        // Graphics Work button
        frm.add_custom_button(__('Create Graphics Work'), function() {
            frappe.call({
                method: 'frappe.client.get_list',
                args: {
                    doctype: 'Graphics Work',
                    filters: { sales_order: frm.doc.name },
                    fields: ['name']
                },
                callback: function(response) {
                    const graphics_works = response.message || [];
                    if (graphics_works.length > 0) {
                        frappe.msgprint(__('Graphics work already created.'));
                        frappe.set_route('Form', 'Graphics Work', graphics_works[0].name);
                    } else {
                        const new_graphics_work = frappe.model.get_new_doc('Graphics Work');
                        new_graphics_work.sales_order = frm.doc.name;
                        frappe.set_route('Form', 'Graphics Work', new_graphics_work.name);
                    }
                }
            });
        });
    },

    custom_final_height(frm) {
        updateCustomerRate(frm, frm.doc.custom_final_height).then(() => {
            if (!isDocSubmitted(frm)) updateBillingAmount(frm);
        });
    },

    custom_jobtype(frm) {
        updateFieldVisibility(frm);

        if (frm.doc.custom_final_height) {
            const height = frm.doc.custom_final_height;
            updateCustomerRate(frm, height).then(() => {
                calculateValues(frm);
                if (!isDocSubmitted(frm)) updateBillingAmount(frm);
            });
        }
    },

    custom_dcrc_rate(frm) {
        calculateValues(frm);
        if (!isDocSubmitted(frm)) updateBillingAmount(frm);
    },

    custom_special_rate(frm) {
        updateCustomerRate(frm, frm.doc.custom_final_height).then(() => {
            calculateValues(frm);
            if (!isDocSubmitted(frm)) updateBillingAmount(frm);
        });
    },

    custom_special_reengraving_rate(frm) {
        updateCustomerRate(frm, frm.doc.custom_final_height).then(() => {
            calculateValues(frm);
            if (!isDocSubmitted(frm)) updateBillingAmount(frm);
        });
    },

    validate(frm) {
        // Cylinder count validation
        const custom_no_of_cylinders = frm.doc.custom_no_of_cylinders || 0;
        const color_details_count = frm.doc.custom_color_details ? frm.doc.custom_color_details.length : 0;

        if (custom_no_of_cylinders !== color_details_count) {
            frappe.msgprint(__('Number of cylinders ({0}) must equal records in color details ({1})', [
                custom_no_of_cylinders,
                color_details_count
            ]));
            frappe.validated = false;
        }

        // Items table validation - only for draft documents
        if (frm.doc.docstatus === 0 && (!frm.doc.items || frm.doc.items.length === 0)) {
            frappe.throw(__("Items table cannot be empty. Please add at least one item."));
        }
    }
});

let original_settings = frappe.listview_settings['Sales Order'] || {};

original_settings.button = {
    show: function(doc) {
        return true; // Always show the button
    },
    
    get_label: function(doc) {
        const salesOrder = doc.name;
        let buttonLabel = __("No Work Order");

        // Fetch the work order status
        frappe.call({
            method: "frappe.client.get_value",
            args: {
                doctype: "Work Order",
                filters: { "sales_order": salesOrder },
                fieldname: "status"
            },
            async: false, // It's recommended to avoid async: false
            callback: function(r) {
                if (r.message && r.message.status) {
                    buttonLabel = r.message.status;
                    // console.log ("Status", buttonLabel);
                }
            }
        });
        return buttonLabel; // Return the status or the initial label
    },
    
    get_description: function(doc) {
        const salesOrder = doc.name; 
        let description = __("Click to open the Work Order");

        // Fetch the work order name for description
        frappe.call({
            method: "frappe.client.get_value",
            args: {
                doctype: "Work Order",
                filters: { "sales_order": salesOrder },
                fieldname: "name"
            },
            async: false, // It's recommended to avoid async: false
            callback: function(r) {
                if (r.message && r.message.name) {
                    description += ` (${r.message.name})`;
                }
            }
        });

        return description; // Return the description
    },
    
    action: function(doc) {
        const salesOrder = doc.name;
        frappe.call({
            method: "frappe.client.get_value",
            args: {
                doctype: "Work Order",
                filters: { "sales_order": salesOrder },
                fieldname: "name"
            },
            callback: function(r) {
                if (r.message && r.message.name) {
                    const workOrder = r.message.name;
                    frappe.set_route("Form", "Work Order", workOrder);
                } else {
                    frappe.msgprint("No Work Order found for Sales Order " + salesOrder);
                }
            }
        });
    }
};

// Merge the original settings with your custom settings
$.extend(true, original_settings, original_settings);

frappe.listview_settings['Sales Order'] = original_settings;

frappe.listview_settings['Sales Order'] = {
