frappe.ui.form.on('Work Order', {
    onload: function(frm) {
        // Automatically execute data fetching when the form is loaded
        if (frm.doc.status === 'Draft' && frm.doc.sales_order) {
            fetch_custom_color_details(frm);
        }
    },
    sales_order: function(frm) {
        // Fetch data when the sales order changes
        if (frm.doc.sales_order) {
            fetch_custom_color_details(frm);
        } else {
            // Clear the table if no sales order is selected
            frm.clear_table('custom_color_details');
            frm.refresh_field('custom_color_details');
        //    console.log("Cleared custom color details due to no sales order selection");
        }
    }
});

function fetch_custom_color_details(frm) {
  //  console.log("Fetching custom color details for sales order:", frm.doc.sales_order);
    
    frappe.call({
        method: 'frappe.client.get',
        args: {
            doctype: 'Sales Order',
            filters: {
                name: frm.doc.sales_order
            }
        },
        callback: function(r) {
        //    console.log("Response from Sales Order call:", r); // Log the response
            
            if (r.message) {
                // Check if custom_color_details has existing data
                if (frm.doc.custom_color_details && frm.doc.custom_color_details.length > 0) {
          //          console.log("Existing data in custom color details, not clearing it.");
                } else {
                    // Clear existing custom color details table rows only if it is empty
                    frm.clear_table('custom_color_details');
            //        console.log("Cleared existing custom color details");
                }

                // Check if custom_color_details exists in the response
                if (r.message.custom_color_details && r.message.custom_color_details.length) {
              //      console.log("Fetched custom color details:", r.message.custom_color_details); // Log fetched details
                    frm.clear_table('custom_color_details')
                    // Iterate through the fetched data from custom_color_details and populate the table
                    r.message.custom_color_details.forEach(function(item) {
                        let child = frm.add_child('custom_color_details');
                        child.color_name = item.color_name;
                        child.panton_code = item.panton_code;
                        child.cylinder_no = item.cylinder_no;
                        // Add other child table fields as needed
                    });

                    // Refresh the child table to show updated data
                    frm.refresh_field('custom_color_details');
            //        console.log("Populated custom color details table");
                } else {
                    console.log("No custom color details found in the sales order response");
                }
            } else {
                console.log("No message in response, check if sales order exists");
            }
        },
        error: function(err) {
            console.error("Error fetching Sales Order:", err); // Log any errors
        }
    });
}

frappe.ui.form.on('Job Card', {
    after_workflow_action: (frm) => {
        // Define a mapping of workflow states to custom fields
        const stateFieldMapping = {
            'Fabrication In Process': 'custom_fabrication_start',
            'Fabrication Complete': 'custom_fabrication_end',
            'Copper Platting in Progress': 'custom_platting_start',
            'Plating Completed': 'custom_platting_end',
            'Copper Cutting In Process': 'custom_cutting_start',
            'Cutting Completed': 'custom_cutting_end',
            'Polishing in Process': 'custom_polishing_start',
            'Polishing Completed': 'custom_polishing_end',
            'Engraving in Process': 'custom_engraving_start',
            'Engraving Complete': 'custom_engraving_end',
            'Chrome In Progress': 'custom_chrome_start',
            'Chrome Completed': 'custom_chrome_end',
