function fetch_custom_color(frm) {
    const jobCardID = frm.doc.job_card_id || frm.doc.name; 
    const sequence_match = jobCardID ? jobCardID.match(/-(\d+)$/) : null;
    const sequence_no = sequence_match ? parseInt(sequence_match[1]) : null;

    if (frm.doc.custom_sales_order && sequence_no) {
        frappe.call({
            method: 'frappe.client.get',
            args: {
                doctype: 'Sales Order',
                filters: { name: frm.doc.custom_sales_order }
            },
            callback: function(r) {
                if (r.message && r.message.custom_color_details && r.message.custom_color_details.length) {
                    const color_details = r.message.custom_color_details;

                    if (sequence_no > 0 && sequence_no <= color_details.length) {
                        const newColor = color_details[sequence_no - 1].color_name;
                        frm.set_value('custom_cylinder_color', newColor);

                        // Optional: Show a message that the value was set
                        // Show an alert or console log here instead of auto-saving
                        //console.log(`Custom cylinder color set to: ${newColor}`);
                    } else {
                        frm.set_value('custom_cylinder_color', '');
                    }
                } else {
                    frm.set_value('custom_cylinder_color', '');
                }
            },
            error: function(err) {
                console.error("Error fetching Sales Order:", err);
            }
        });
    } else {
        frm.set_value('custom_cylinder_color', '');
    }
}

