frappe.ui.form.on("Quotation", {
    refresh(frm) {
        frm.add_custom_button("Get Items from Sales Order", function () {
            let selected_so = [];

            const dialog = new frappe.ui.Dialog({
                title: "Select Sales Orders",
                fields: [
                    { fieldname: "results_area", fieldtype: "HTML" }
                ],
                primary_action_label: "Get Items",
                primary_action() {
                    if (!selected_so.length) {
                        frappe.msgprint("Please select at least one Sales Order.");
                        return;
                    }
                    dialog.hide();
                    frm.clear_table("items");

                    selected_so.forEach(so_name => {
                        frappe.call({
                            method: "frappe.client.get",
                            args: { doctype: "Sales Order", name: so_name },
                            callback({ message: so }) {
                                if (!so) return;

                                (so.items || []).forEach(item => {
                                    frm.add_child("items", {
                                        item_code: item.item_code,
                                        item_name: item.item_name,
                                        qty: item.qty,
                                        uom: item.uom,
                                        rate: item.rate,
                                        amount: item.amount,
                                        hsn_sac: item.gst_hsn_code,
                                        custom_sales_order_id: so.name,
                                        custom_job_name: so.custom_job_name,
                                        custom_circum: so.custom_final_height,
                                        custom_width: so.custom_full_width
                                    });
                                });
                                frm.refresh_field("items");
                            }
                        });
                    });
                }
            });

            dialog.show();
            dialog.$wrapper.find(".modal-dialog").css({
                width: "95%",
                maxWidth: "1300px"
            });

            const wrapper = dialog.fields_dict.results_area.$wrapper;
            const table_id = "sales-order-selection-table";

            wrapper.html(`
                <div style="max-height: 420px; overflow: auto;">
                    <table class="table table-bordered table-sm" id="${table_id}">
                        <thead class="table-light">
                            <tr>
                                <th style="width: 30px;"></th>
                                <th style="width: 100px;">Sales Order</th>
                                <th style="width: 200px;">Job Name</th>
                                <th style="width: 60px;">Cyl</th>
                                <th style="width: 100px;">Job Type</th>
                                <th style="width: 70px;">Circ</th>
                                <th style="width: 70px;">Width</th>
                            </tr>
                            <tr>
                                <th></th>
                                <th><input class="form-control form-control-sm" data-name="name" /></th>
                                <th><input class="form-control form-control-sm" data-name="custom_job_name" style="max-width: 300px;" /></th>
                                <th><input class="form-control form-control-sm" type="number" data-name="custom_no_of_cylinders" /></th>
                                <th>
                                    <select class="form-control form-control-sm" data-name="custom_jobtype">
                                        <option value="">All</option>
                                    </select>
                                </th>
                                <th><input class="form-control form-control-sm" type="number" data-name="custom_final_height" /></th>
                                <th><input class="form-control form-control-sm" type="number" data-name="custom_full_width" /></th>
                            </tr>
                        </thead>
                        <tbody></tbody>
                    </table>
                </div>
            `);

            const $table = wrapper.find(`#${table_id}`);
            const $filters = $table.find("thead").find("tr:eq(1)");
            const $select = $filters.find('[data-name="custom_jobtype"]');

            function getFilters() {
                const filters = {
                    customer: frm.doc.party_name,
                    status: ["not in", ["Completed", "Cancelled"]]
                };

                $filters.find("[data-name]").each(function () {
                    const $el = $(this);
                    const key = $el.attr("data-name");
                    const val = $el.val();
                    if (val) {
                        if (["name", "custom_job_name"].includes(key)) {
                            filters[key] = ["like", `%${val}%`];
                        } else {
                            filters[key] = val;
                        }
                    }
                });
                return filters;
            }

            function fetchSalesOrders() {
                frappe.call({
                    method: "frappe.client.get_list",
                    args: {
                        doctype: "Sales Order",
                        fields: [
                            "name",
                            "custom_job_name",
                            "custom_no_of_cylinders",
                            "custom_jobtype",
                            "custom_final_height",
                            "custom_full_width"
                        ],
                        filters: getFilters(),
                        limit: 100
                    },
                    callback({ message: data }) {
                        const tbody = $table.find("tbody");
                        tbody.empty();

                        if (!$select.data("initialized") && data.length) {
                            const options = [...new Set(data.map(d => d.custom_jobtype).filter(Boolean))];
                            options.forEach(opt =>
                                $select.append(`<option value="${opt}">${opt}</option>`)
                            );
                            $select.data("initialized", true);
                        }

                        if (!data.length) {
                            tbody.append(`<tr><td colspan="7" class="text-center text-muted">No results found</td></tr>`);
                            return;
                        }

                        data.forEach(row => {
                            tbody.append(`
                                <tr>
                                    <td><input type="checkbox" class="so-select" value="${row.name}" ${selected_so.includes(row.name) ? "checked" : ""} /></td>
                                    <td>${row.name}</td>
                                    <td>${row.custom_job_name || ""}</td>
                                    <td>${row.custom_no_of_cylinders || ""}</td>
                                    <td>${row.custom_jobtype || ""}</td>
                                    <td>${row.custom_final_height || ""}</td>
                                    <td>${row.custom_full_width || ""}</td>
                                </tr>
                            `);
                        });

                        tbody.find(".so-select").on("change", function () {
                            const val = $(this).val();
                            if (this.checked && !selected_so.includes(val)) {
                                selected_so.push(val);
                            } else {
                                selected_so = selected_so.filter(v => v !== val);
                            }
                        });
                    }
                });
            }

            $filters.find("input,select").on("change keyup", frappe.utils.debounce(fetchSalesOrders, 300));
            fetchSalesOrders();
        });
    }
});

