const doctypeName = 'Sales Order';
frappe.listview_settings[doctypeName] = frappe.listview_settings[doctypeName] || {};

frappe.listview_settings[doctypeName].refresh = function(listview) {
    listview.$page.find('.list-row').each(function() {
        const $row = $(this);
        const jobtypeElement = $row.find('[title^="JobType:"]');

        if (jobtypeElement.length) {
            const jobtypeValue = jobtypeElement.attr('title').split(':').pop().trim();

            // Define groups of job types for each color
            const tealJobTypes = ["FABG", "CFAB"];
            const lightRedJobTypes = ["SUPG", "CSUP"];
            const lightGreyJobTypes = ["SFOC", "CFOC", "AIIR"];

            // Assign colors based on the job type group
            let bgColor = "#ffffff"; // Default white
            let textColor = "#000000"; // Default black
            
            if (tealJobTypes.includes(jobtypeValue)) {
                bgColor = "#57C5B6";
                textColor = "#ffffff";
            } else if (lightRedJobTypes.includes(jobtypeValue)) {
                bgColor = "#e49393";
            } else if (lightGreyJobTypes.includes(jobtypeValue)) {
                bgColor = "#e9e9e9";
            }

            // Find and style specific columns by their title text
            const columnsToStyle = [
                { titleText: "Customer", element: null },
                { titleText: "Shipping Address", element: null },
                { titleText: "Date", element: null }
            ];

            // First: Find all cells and cache matching elements
            $row.find('.list-row__cell').each(function() {
                const $cell = $(this);
                const title = $cell.attr('title') || '';
                
                columnsToStyle.forEach(col => {
                    if (title.includes(col.titleText)) {
                        col.element = $cell;
                    }
                });
            });

            // Second: Apply styles to found elements
            columnsToStyle.forEach(col => {
                if (col.element) {
                    col.element.css({
                        "background-color": bgColor,
                        "color": textColor,
                        "padding": "3px 6px",
                        "border-radius": "3px",
                        "font-weight": "bold"
                    });
                }
            });
        }
    });
};

function extend_listview_event(doctype, event, callback) { 
    if (!frappe.listview_settings[doctype]) {
        frappe.listview_settings[doctype] = {};
    }

    const old_event = frappe.listview_settings[doctype][event]; 
    frappe.listview_settings[doctype][event] = function (listview) { 
        if (old_event) {
            old_event(listview);
        }
        callback(listview);
    };
}

extend_listview_event("Sales Order", "refresh", function (listview) {
    if (window.innerWidth > 768) {
        // Configuration
        const headerExcludedFields = ["JobType", "No of Cylinders", "Circum", "Width", "TMM", "Status"];
        const dataFields = ["custom_jobtype", "custom_no_of_cylinders", "custom_final_height", 
                           "custom_full_width", "custom_cylinder_tmm", "docstatus"];
        const excludedWidth = '100px';
        const defaultWidth = '200px';
        
        // Set header column widths
        document.querySelectorAll('.list-row-col').forEach(col => { 
            const fieldText = col.innerText.trim();
            const isExcluded = headerExcludedFields.some(field => fieldText.includes(field));
            
            col.style.minWidth = isExcluded ? excludedWidth : defaultWidth;
            col.style.maxWidth = isExcluded ? excludedWidth : defaultWidth;
        });
        
        // Set data cell widths
        dataFields.forEach(field => {
            // Use a selector that matches data-filter containing the field name
            document.querySelectorAll(`.filterable[data-filter*="${field}"]`).forEach(cell => {
                const parentCell = cell.closest('.list-row-col');
                if (parentCell) {
                    parentCell.style.minWidth = excludedWidth;
                    parentCell.style.maxWidth = excludedWidth;
                }
            });
            
            // Also check for data-fieldname attribute as a fallback
            document.querySelectorAll(`[data-fieldname="${field}"]`).forEach(cell => {
                const parentCell = cell.closest('.list-row-col');
                if (parentCell) {
