frappe.ui.form.on('Sales Order', {
    refresh: function(frm) {
        const isProofingUser = frappe.user_roles.includes("Proofing User");

        if (isProofingUser) {
            // Sections you want to keep visible
            const allowedSections = [
                "customer_section",
                "shipping_address_column",
                "custom_size",
                "custom_section_break_7ynyk",
                "custom_section_break_ofatb",
                "custom_printing",
                "custom_special_instruction"
            ];

            frm.fields.forEach(field => {
                if (field.df.fieldtype === "Section Break" || field.df.fieldtype === "Column Break") {
                    // Hide all sections/columns except the allowed ones
                    if (!allowedSections.includes(field.df.fieldname)) {
                        frm.set_df_property(field.df.fieldname, "hidden", 1);
                    } else {
                        frm.set_df_property(field.df.fieldname, "hidden", 0);
                    }
                }
            });

            // Additionally, lock all fields outside allowed sections
            frm.fields.forEach(field => {
                if (!allowedSections.includes(field.df.fieldname)) {
                    frm.set_df_property(field.df.fieldname, "read_only", 1);
                }
            });
        }
    }
});

