// ============================
// CONSTANTS
// ============================

// Fields that affect cylinder calculations
const CALC_FIELDS = new Set([
    'custom_design_hight', 'custom_steps', 'custom_design_width',
    'custom_repeats', 'custom_r_width', 'custom_additional_width',
    'custom_pie_value', 'custom_fab_roll', 'custom_sup_roll'
]);

// Fields that affect billing amount
const BILLING_FIELDS = new Set([
    'custom_fab_roll', 'custom_sup_roll',
    'custom_customer_rate', 'custom_customer_reengraving_rate',
    'custom_no_of_cylinders', 'custom_cylinder_tmm'
]);

// Job type groups
const FAB_GROUP    = new Set(["FABG", "CFAB"]);
const SUP_GROUP    = new Set(["SUPG", "CSUP"]);
const FOC_GROUP    = new Set(["SFOC", "CFOC", "AIIR"]);
const RETURN_GROUP = new Set(["AIIR"]);
const DCRC_GROUP   = new Set(["DCRC"]);
const MIX_GROUP    = new Set(["MIX"]);
const SHOW_FAB_GROUP = new Set(["FABG", "CFAB", "MIX"]);
const SHOW_SUP_GROUP = new Set(["SUPG", "CSUP", "SFOC", "CFOC", "AIIR", "DCRC", "MIX"]);

const RELEVANT_ITEM_CODES = new Set([
    "Engraving Cylinder", "Engraving Cylinder Supplied",
    "Engraving Cylinder FOC", "Engraving Cylinder as is Return"
]);

// Single DB call fetches both custom_f and custom_s rate fields at once
const RATE_FETCH_FIELDS = [
    'custom_f400', 'custom_f600', 'custom_f800',
    'custom_f1000', 'custom_f1500', 'custom_f2000',
    'custom_s400', 'custom_s600', 'custom_s800',
    'custom_s1000', 'custom_s1500', 'custom_s2000'
];

// Workflow action → { fields to stamp with today's date }
const WORKFLOW_FIELD_MAP = {
    'Roll Processing': {
        fields: ['custom_fabrication_start']
    },
    'Send for Engraving': {
        fields: ['custom_engraving_start', 'custom_fabrication_end']
    },
    'Send for Proofing': {
        fields: ['custom_proofing_start', 'custom_engraving_end']
    },
    'Send for Billing': {
        fields: ['custom_proofing_end']
    }
};

// ============================
// BILLING ADDRESS ENFORCEMENT
// ============================

// Validate that customer_address follows the naming convention: {customer_name}-Billing
// Returns true if valid, false if not. Does NOT show any alert.
const isBillingAddressValid = (frm) => {
    if (!frm.doc.customer || !frm.doc.customer_address) {
        return true;
    }
    const expected = `${frm.doc.customer_name}-Billing`;
    const actual = frm.doc.customer_address;
    return actual === expected;
};

// Auto-select the correct billing address (no duplicate alert)
const setBillingAddress = (frm) => {
    if (!frm.doc.customer) return;

    const expectedName = `${frm.doc.customer_name}-Billing`;

    frappe.call({
        method: 'frappe.client.get_list',
        args: {
            doctype: 'Address',
            filters: [
                ['name', '=', expectedName],
                ['Dynamic Link', 'link_doctype', '=', 'Customer'],
                ['Dynamic Link', 'link_name', '=', frm.doc.customer]
            ],
            fields: ['name'],
            limit: 1
        },
        callback: function(r) {
            if (r.message && r.message.length) {
                frm._settingAddress = true;
                frm.set_value('customer_address', expectedName);
                frm._settingAddress = false;
            } else {
                frappe.call({
                    method: 'frappe.client.get_list',
                    args: {
                        doctype: 'Address',
                        filters: [
                            ['Dynamic Link', 'link_doctype', '=', 'Customer'],
                            ['Dynamic Link', 'link_name', '=', frm.doc.customer],
                            ['address_title', 'like', '%Billing%']
                        ],
                        fields: ['name', 'address_title'],
                        limit: 1
                    },
                    callback: function(res) {
                        if (res.message && res.message.length) {
                            frm._settingAddress = true;
                            frm.set_value('customer_address', res.message[0].name);
                            frm._settingAddress = false;
                        } else {
                            frappe.show_alert({
                                message: __('No billing address found for this customer. Please create one.'),
                                indicator: 'orange'
                            }, 10);
                        }
                    }
                });
            }
        }
    });
};

// ============================
// HELPER FUNCTIONS
// ============================

const isDocSubmitted = (frm) => frm.doc.docstatus === 1;

const safeSetValue = (frm, field, value) => {
    if (isDocSubmitted(frm)) {
        frm.doc[field] = value;
        frm.refresh_field(field);
    } else {
        frm.set_value(field, value);
    }
};

// Get rate from pre-fetched values object based on height range
const getRateFromValues = (values, prefix, height) => {
    if (height > 1    && height <= 400)  return values[`${prefix}400`]  || 0;
    if (height > 400  && height <= 600)  return values[`${prefix}600`]  || 0;
    if (height > 600  && height <= 800)  return values[`${prefix}800`]  || 0;
    if (height > 800  && height <= 1000) return values[`${prefix}1000`] || 0;
    if (height > 1000 && height <= 1500) return values[`${prefix}1500`] || 0;
    if (height > 1500 && height <= 2000) return values[`${prefix}2000`] || 0;
    return 0;
};

// Single DB call fetches both custom_f and custom_s rates at once
const updateCustomerRate = (frm, height) => {
    return new Promise((resolve) => {
        if (!frm.doc.customer || !height) return resolve();
        frappe.db.get_value('Customer', frm.doc.customer, RATE_FETCH_FIELDS, (values) => {
            if (!values) return resolve();
            const customerRate = frm.doc.custom_special_rate || getRateFromValues(values, 'custom_f', height);
            const reengravRate = frm.doc.custom_special_reengraving_rate || getRateFromValues(values, 'custom_s', height);
            safeSetValue(frm, 'custom_customer_rate', customerRate);
            safeSetValue(frm, 'custom_customer_reengraving_rate', reengravRate);
            resolve();
        });
    });
};

// Calculate pipe thickness based on diameter
const calculatePipeThickness = (dia) => dia <= 273 ? 8 : dia <= 356 ? 10 : 12;

// Calculate pipe weight in kg
const calculatePipeKg = (outerDia, thickness, length) => {
    try {
        const innerDia = outerDia - 2 * flt(thickness);
        const volume = Math.PI * ((outerDia / 2) ** 2 - (innerDia / 2) ** 2) * flt(length);
        return (volume / 1000000) * 7.85;
    } catch (e) {
        return 0;
    }
};

// Calculate all cylinder values in one pass
const calculateValues = (frm) => {
    try {
        const doc = frm.doc;

        const designHeight = flt(doc.custom_design_hight);
        const steps        = flt(doc.custom_steps);
        const designWidth  = flt(doc.custom_design_width);
        const repeats      = flt(doc.custom_repeats);
        const rWidth       = flt(doc.custom_r_width);
        const additionalW  = flt(doc.custom_additional_width);
        const pieValue     = flt(doc.custom_pie_value);
        const fabRoll      = flt(doc.custom_fab_roll);
        const supRoll      = flt(doc.custom_sup_roll);

        const numCylinders  = fabRoll + supRoll;
        const finalHeight   = parseFloat((designHeight * steps).toFixed(2));
        const materialWidth = parseFloat((designWidth * repeats).toFixed(2));
        const fullWidth     = parseFloat((materialWidth + rWidth + additionalW).toFixed(2));
        const finalDia      = finalHeight / 3.1416;
        const msDia         = parseFloat((finalHeight < 850 ? finalDia - 0.20 : finalDia - 0.25).toFixed(2));
        const cylinderDia   = parseFloat((finalHeight / pieValue).toFixed(2));
        const singleTMM     = parseFloat((finalHeight * fullWidth / 1000).toFixed(2));
        const totalTMM      = parseFloat((singleTMM * numCylinders).toFixed(2));
        const pipeDia       = Math.round(cylinderDia + 3);
        const pipeThickness = calculatePipeThickness(cylinderDia);
        const pipeKg        = parseFloat(calculatePipeKg(pipeDia, pipeThickness, fullWidth).toFixed(2));

        const updates = {
            custom_no_of_cylinders:   numCylinders,
            custom_final_height:      finalHeight,
            custom_material_width:    materialWidth,
            custom_full_width:        fullWidth,
            custom_final_dia:         parseFloat(finalDia.toFixed(2)),
            custom_ms_dia:            msDia,
            custom_cylinder_diameter: cylinderDia,
            custom_single_tmm:        singleTMM,
            custom_cylinder_tmm:      totalTMM,
            custom_pipe_diameter:     pipeDia,
            custom_pipe_thickness:    pipeThickness,
            custom_pipe_kg:           pipeKg
        };

        Object.entries(updates).forEach(([field, value]) => safeSetValue(frm, field, value));

    } catch (e) {
        console.error("Error in calculateValues:", e);
    }
};

// Rebuild billing items
const updateBillingAmount = (frm) => {
    try {
        if (isDocSubmitted(frm) || !frm.doc.items) return;

        const doc          = frm.doc;
        const jobType      = doc.custom_jobtype;
        const deliveryDate = doc.delivery_date;
        const numCyl       = flt(doc.custom_no_of_cylinders) || 1;
        const tmm_per_cyl  = flt(doc.custom_cylinder_tmm) / numCyl;
        const fabRoll      = flt(doc.custom_fab_roll);
        const supRoll      = flt(doc.custom_sup_roll);
        const custRate     = flt(doc.custom_customer_rate);
        const reengravRate = flt(doc.custom_customer_reengraving_rate);
        const dcrcRate     = flt(doc.custom_dcrc_rate);

        let itemsToAdd = [];

        if (FAB_GROUP.has(jobType)) {
            itemsToAdd.push({ code: "Engraving Cylinder", qty: fabRoll, rate: custRate * tmm_per_cyl });
        } else if (SUP_GROUP.has(jobType)) {
            itemsToAdd.push({ code: "Engraving Cylinder Supplied", qty: supRoll, rate: reengravRate * tmm_per_cyl });
        } else if (DCRC_GROUP.has(jobType)) {
            itemsToAdd.push({ code: "Engraving Cylinder Supplied", qty: supRoll, rate: dcrcRate * tmm_per_cyl });
        } else if (FOC_GROUP.has(jobType)) {
            itemsToAdd.push({ code: "Engraving Cylinder FOC", qty: numCyl, rate: 0 });
        } else if (RETURN_GROUP.has(jobType)) {
            itemsToAdd.push({ code: "Engraving Cylinder as is Return", qty: numCyl, rate: 0 });
        } else if (MIX_GROUP.has(jobType)) {
            itemsToAdd.push(
                { code: "Engraving Cylinder", qty: fabRoll, rate: custRate * tmm_per_cyl },
                { code: "Engraving Cylinder Supplied", qty: supRoll, rate: reengravRate * tmm_per_cyl }
            );
        } else {
            itemsToAdd.push({ code: "Engraving Cylinder", qty: numCyl, rate: 0 });
        }

        // Remove old relevant items, keep everything else
        frm.doc.items = frm.doc.items.filter(item =>
            item.item_code && flt(item.qty) > 0 && !RELEVANT_ITEM_CODES.has(item.item_code)
        );

        // Add new items
        itemsToAdd.forEach(({ code, qty, rate }) => {
            if (!qty || qty <= 0) return;
            frm.add_child("items", {
                item_code: code, item_name: code,
                uom: "Nos", conversion_factor: 1,
                qty: Math.round(flt(qty)),
                delivery_date: deliveryDate,
                rate: parseFloat(flt(rate)).toFixed(2)
            });
        });

        frm.refresh_field("items");
    } catch (e) {
        console.error("Error in updateBillingAmount:", e);
    }
};

// Smart field change handler
const handleCustomFieldChange = (frm, fieldname) => {
    if (frm._updatingVisibility) return;
    const needsCalc    = CALC_FIELDS.has(fieldname);
    const needsBilling = BILLING_FIELDS.has(fieldname);

    if (needsCalc) calculateValues(frm);

    if (needsBilling && !isDocSubmitted(frm)) {
        updateBillingAmount(frm);
    } else if (needsCalc && !isDocSubmitted(frm)) {
        updateBillingAmount(frm);
    }
};

// Update field visibility based on job type
const updateFieldVisibility = (frm) => {
    const jobType = frm.doc.custom_jobtype;

    frm._updatingVisibility = true;
    safeSetValue(frm, 'custom_fab_roll', 0);
    safeSetValue(frm, 'custom_sup_roll', 0);
    frm._updatingVisibility = false;

    const visibility = {
        custom_fab_roll:                  SHOW_FAB_GROUP.has(jobType),
        custom_sup_roll:                  SHOW_SUP_GROUP.has(jobType),
        custom_dcrc_rate:                 DCRC_GROUP.has(jobType),
        custom_special_rate:              SHOW_FAB_GROUP.has(jobType),
        custom_special_reengraving_rate:  SHOW_SUP_GROUP.has(jobType) && !FOC_GROUP.has(jobType),
        custom_customer_rate:             SHOW_FAB_GROUP.has(jobType),
        custom_customer_reengraving_rate: SHOW_SUP_GROUP.has(jobType) && !FOC_GROUP.has(jobType)
    };

    Object.entries(visibility).forEach(([field, show]) => {
        frm.set_df_property(field, 'hidden', !show);
    });

    frm.refresh_fields(Object.keys(visibility));
};

// ============================
// WORKFLOW DATE TRACKING
// ============================
const setupWorkflowTracking = (frm) => {
    // Store current docname, reset tracking if navigated to different doc
    if (frappe.call._workflow_tracking_frm === frm.doc.name) return;
    
    // If already wrapped, restore original before re-wrapping
    if (frappe.call._workflow_original) {
        frappe.call = frappe.call._workflow_original;
    }

    const original_call = frappe.call;

    frappe.call = function(opts) {
        if (!opts || !opts.args) return original_call.apply(this, arguments);

        // Status > Close
        if (opts.method && opts.method.includes('update_status')) {
            if (opts.args.status === 'Closed') {
                const today = frappe.datetime.get_today();
                const fieldname = {};
                if (!frm.doc.custom_closed)       fieldname['custom_closed']       = today;
                if (!frm.doc.custom_proofing_end)  fieldname['custom_proofing_end'] = today;

                if (Object.keys(fieldname).length > 0) {
                    const original_callback = opts.callback;
                    original_call.call(this, {
                        method: 'frappe.client.set_value',
                        args: {
                            doctype: 'Sales Order',
                            name: frm.doc.name,
                            fieldname: fieldname
                        },
                        callback: function(r) {
                            opts.callback = original_callback;
                            original_call.call(this, opts);
                        }
                    });
                    return;
                }
            }
        }

        // Workflow Transitions
        if (opts.method && opts.method.includes('apply_workflow')) {
            const entry = WORKFLOW_FIELD_MAP[opts.args.action];
            if (entry) {
                const today = frappe.datetime.get_today();
                const fieldname = {};
                entry.fields.forEach(f => {
                    if (!frm.doc[f]) fieldname[f] = today;
                });

                if (Object.keys(fieldname).length > 0) {
                    const original_callback2 = opts.callback;
                    original_call.call(this, {
                        method: 'frappe.client.set_value',
                        args: {
                            doctype: 'Sales Order',
                            name: frm.doc.name,
                            fieldname: fieldname
                        },
                        callback: function(r) {
                            opts.callback = original_callback2;
                            original_call.call(this, opts);
                        }
                    });
                    return;
                }
            }
        }

        return original_call.apply(this, arguments);
    };

    frappe.call._workflow_original = original_call;
    frappe.call._workflow_tracking_frm = frm.doc.name;
};

// ============================
// SALES ORDER FORM CONTROLS
// ============================
frappe.ui.form.on("Sales Order", {
    refresh(frm) {
        if (isDocSubmitted(frm)) {
            frm.enable_save();
            frm.set_df_property('items', 'read_only', 1);
            const submitFields = [
                'custom_customer_rate', 'custom_customer_reengraving_rate',
                'custom_special_rate', 'custom_special_reengraving_rate',
                'custom_dcrc_rate', 'custom_final_height', 'custom_jobtype',
                'custom_fab_roll', 'custom_sup_roll', 'custom_no_of_cylinders',
                'custom_design_hight', 'custom_steps', 'custom_design_width',
                'custom_repeats', 'custom_r_width', 'custom_additional_width',
                'custom_pie_value'
            ];
            submitFields.forEach(field => {
                frm.set_df_property(field, 'allow_on_submit', 1);
                frm.set_df_property(field, 'read_only', 0);
            });
        }

        // Attach onchange to watched fields
        const watchedFields = new Set([...CALC_FIELDS, ...BILLING_FIELDS]);
        watchedFields.forEach(field => {
            if (frm.fields_dict[field]) {
                frm.fields_dict[field].df.onchange = () => handleCustomFieldChange(frm, field);
            }
        });

        frm.fields_dict['delivery_date'].df.onchange = () => {
            if (!isDocSubmitted(frm)) updateBillingAmount(frm);
        };

        frm.add_custom_button(__('Create Graphics Work'), function() {
            frappe.call({
                method: 'frappe.client.get_list',
                args: {
                    doctype: 'Graphics Work',
                    filters: { sales_order: frm.doc.name },
                    fields: ['name']
                },
                callback: function(response) {
                    const graphics_works = response.message || [];
                    if (graphics_works.length > 0) {
                        frappe.msgprint(__('Graphics work already created.'));
                        frappe.set_route('Form', 'Graphics Work', graphics_works[0].name);
                    } else {
                        const new_graphics_work = frappe.model.get_new_doc('Graphics Work');
                        new_graphics_work.sales_order = frm.doc.name;
                        frappe.set_route('Form', 'Graphics Work', new_graphics_work.name);
                    }
                }
            });
        });

        setupWorkflowTracking(frm);
    },

    // When customer is selected, auto‑set the correct billing address
    customer(frm) {
        setBillingAddress(frm);
    },

    // When user manually changes the address, validate (but skip if we are setting it programmatically)
    customer_address(frm) {
    if (frm._settingAddress) return;

    const expected = `${frm.doc.customer_name}-Billing`;
    const actual = frm.doc.customer_address;

    if (actual && actual !== expected) {
        // Mismatch – set to expected pattern (WARNING: this may cause invalid link error if address doesn't exist)
        frm._settingAddress = true;
        frm.set_value('customer_address', expected);
        frm._settingAddress = false;
        frappe.msgprint({
            title: __('Billing Address Updated'),
            indicator: 'orange',
            message: __(`Address changed from "${actual}" to "${expected}". Please ensure this address exists.`)
        });
    }
},

    custom_final_height(frm) {
        updateCustomerRate(frm, frm.doc.custom_final_height).then(() => {
            if (!isDocSubmitted(frm)) updateBillingAmount(frm);
        });
    },

    custom_jobtype(frm) {
        updateFieldVisibility(frm);
        if (frm.doc.custom_final_height) {
            updateCustomerRate(frm, frm.doc.custom_final_height).then(() => {
                calculateValues(frm);
                if (!isDocSubmitted(frm)) updateBillingAmount(frm);
            });
        } else {
        // Always update billing regardless of height
        if (!isDocSubmitted(frm)) updateBillingAmount(frm);
        }
    },

    custom_dcrc_rate(frm) {
        calculateValues(frm);
        if (!isDocSubmitted(frm)) updateBillingAmount(frm);
    },

    custom_special_rate(frm) {
        updateCustomerRate(frm, frm.doc.custom_final_height).then(() => {
            calculateValues(frm);
            if (!isDocSubmitted(frm)) updateBillingAmount(frm);
        });
    },

    custom_special_reengraving_rate(frm) {
        updateCustomerRate(frm, frm.doc.custom_final_height).then(() => {
            calculateValues(frm);
            if (!isDocSubmitted(frm)) updateBillingAmount(frm);
        });
    },

    // VALIDATION WITH ENFORCEMENT – block save if billing address is wrong
    validate(frm) {
        const numCyl     = frm.doc.custom_no_of_cylinders || 0;
        const colorCount = frm.doc.custom_color_details ? frm.doc.custom_color_details.length : 0;
        if (numCyl !== colorCount) {
            frappe.msgprint(__('Number of cylinders ({0}) must equal records in color details ({1})', [numCyl, colorCount]));
            frappe.validated = false;
        }
        if (frm.doc.docstatus === 0 && (!frm.doc.items || frm.doc.items.length === 0)) {
            frappe.throw(__("Items table cannot be empty. Please add at least one item."));
        }

        // Enforce billing address naming convention
            if (!isBillingAddressValid(frm)) {
    frappe.msgprint({
        title: __('Warning'),
        indicator: 'orange',
        message: __('Billing address may not match the expected format for this customer.')
            });
    // Not blocking save until address validation is fully tested
        }
    }
});

frappe.ui.form.on('Rejection Entry', {
    job_circum: function(frm) {
        calculate_tmm(frm);
    },
    length: function(frm) {
        calculate_tmm(frm);
    },
    qty: function(frm) {
        calculate_tmm(frm);
    }
});

function calculate_tmm(frm) {
    if (frm.doc.job_circum && frm.doc.length && frm.doc.qty) {
        frm.set_value('tmm', (frm.doc.job_circum * frm.doc.length / 1000) * frm.doc.qty);
    }
}

function extend_listview_event(doctype, event, callback) { 
    if (!frappe.listview_settings[doctype]) {
        frappe.listview_settings[doctype] = {};
    }

    const old_event = frappe.listview_settings[doctype][event]; 
    frappe.listview_settings[doctype][event] = function (listview) { 
        if (old_event) {
            old_event(listview);
        }
        callback(listview);
    };
}

